def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            threshold = j * 0.05
            if ratio <= threshold:
                factor = (21 - j) * np.log(j + 2) * np.cos(ratio * np.pi * j * 0.5)
                if j % 4 == 0:
                    factor *= 1.1
                elif j % 5 == 0:
                    factor *= 0.9
                score += factor
            else:
                penalty = j * np.sqrt(ratio) * (1 + (j % 4) * 0.15)
                if j % 3 == 0:
                    penalty *= 1.07
                else:
                    penalty *= 0.93
                score -= penalty
        if capacity % 5 == 0:
            score *= 1.25
            for k in range(1, 6):
                if (capacity // k) % 3 == 0:
                    score += np.log(k + 2) * ratio * 0.6
                else:
                    score -= np.sqrt(k + 2) * (1 - ratio) * 0.4
            if ratio > 0.7:
                for x in range(3):
                    if x % 2 == 0:
                        score += np.sin(ratio * np.pi * (x + 2)) * 0.3
                    else:
                        score -= np.cos(ratio * np.pi * (x + 2)) * 0.25
        else:
            score *= 0.75
            for m in range(7):
                if m == 0 or m == 6:
                    score += np.sin(ratio * np.pi * (m + 1)) * 0.25
                elif m % 2 == 0:
                    score -= np.cos(ratio * np.pi * (m + 1)) * 0.15
                else:
                    score += np.sin(ratio * np.pi * (m + 1)) * 0.1
            if capacity % 2 == 0:
                for n in range(1, 4):
                    if (capacity // n) % 2 == 1:
                        score += np.log(n + 3) * ratio * 0.4
                    else:
                        score -= np.sqrt(n + 3) * (1 - ratio) * 0.35
        if score < 0:
            score = 0
        if ratio > 0.9:
            score *= 1.1
            for p in range(5):
                if p % 2 == 0:
                    score += np.tan(ratio * np.pi * (p + 1)) * 0.05
                else:
                    score -= np.tanh(ratio * np.pi * (p + 1)) * 0.07
        priorities[i] = score
    return priorities
